$rom = [System.IO.File]::ReadAllBytes('C:\Work\nes1\test\Mappy (Japan).nes')
# 1 PRG page = 16KB, mirrored at 0x8000 and 0xC000
# C72B -> 0x72B bytes into the PRG, offset = 0x72B + 0x10 = 0x73B
# Let's decode some bytes starting there
$offset = 0x073B
$bytes = $rom[$offset..($offset+40)]
# Simple 6502 disassembly
$i = 0
while ($i -lt 30) {
    $b = $bytes[$i]; $pc = 0xC72B + $i
    $s = switch ($b) {
        0xA9 { "LDA #$$('{0:X2}' -f $bytes[$i+1])"; $i+=2; break }
        0xA5 { "LDA \$$$('{0:X2}' -f $bytes[$i+1])"; $i+=2; break }
        0x85 { "STA \$$$('{0:X2}' -f $bytes[$i+1])"; $i+=2; break }
        0x06 { "ASL \$$$('{0:X2}' -f $bytes[$i+1])"; $i+=2; break }
        0x26 { "ROL \$$$('{0:X2}' -f $bytes[$i+1])"; $i+=2; break }
        0x66 { "ROR \$$$('{0:X2}' -f $bytes[$i+1])"; $i+=2; break }
        0x2A { 'ROL A'; $i+=1; break }
        0x29 { "AND #$$('{0:X2}' -f $bytes[$i+1])"; $i+=2; break }
        0xAA { 'TAX'; $i+=1; break }
        0x4C { "JMP \$$$('{0:X2}' -f $bytes[$i+2])$('{0:X2}' -f $bytes[$i+1])"; $i+=3; break }
        0xD0 { $rel=$bytes[$i+1]; if ($rel -gt 127) {$rel=$rel-256}; "BNE \$$$('{0:X4}' -f (0xC72B+$i+2+$rel))"; $i+=2; break }
        0xF0 { $rel=$bytes[$i+1]; if ($rel -gt 127) {$rel=$rel-256}; "BEQ \$$$('{0:X4}' -f (0xC72B+$i+2+$rel))"; $i+=2; break }
        0x90 { $rel=$bytes[$i+1]; if ($rel -gt 127) {$rel=$rel-256}; "BCC \$$$('{0:X4}' -f (0xC72B+$i+2+$rel))"; $i+=2; break }
        0xB0 { $rel=$bytes[$i+1]; if ($rel -gt 127) {$rel=$rel-256}; "BCS \$$$('{0:X4}' -f (0xC72B+$i+2+$rel))"; $i+=2; break }
        0x18 { 'CLC'; $i+=1; break }
        0x38 { 'SEC'; $i+=1; break }
        default { "UNK $('{0:X2}' -f $b)"; $i+=1; break }
    }
    Write-Host ('{0:X4}: {1}' -f $pc, $s)
}
